use std::cmp::{max, min};

struct IntervalTree<T> {
    intervals: Vec<(T, T)>,
}

impl<T: Ord + Copy> IntervalTree<T> {
    fn new(mut intervals: Vec<(T, T)>) -> Self {
        intervals.sort();
        IntervalTree { intervals }
    }

    fn query(&self, start: T, end: T) -> Vec<(T, T)> {
        let mut result = Vec::new();
        for &(s, e) in &self.intervals {
            if s <= end && start <= e {
                result.push((max(start, s), min(end, e)));
            }
        }
        result
    }
}

fn main() {
    let intervals = vec![(1, 5), (3, 7), (8, 9)];
    let tree = IntervalTree::new(intervals.clone());
    println!("{:?}", tree.query(2, 6));
}

