fn build_tree(intervals: Vec<(i32, i32)>) -> Vec<(i32, i32)> {
    intervals
}

fn query(tree: &Vec<(i32, i32)>, start: i32, end: i32) -> usize {
    let overlap = tree.iter().filter(|(s, e)| s < &end && e > &start).count();
    if overlap == 0 { return 0; }
    let total_length: i32 = tree.iter()
        .map(|(_, e)| if e >= &end { end - start } else { e - start })
        .sum();
    (total_length as f64 / overlap as f64).round() as usize
}

fn main() {
    let intervals = vec![(1, 5), (3, 8), (6, 9)];
    let tree = build_tree(intervals);
    println!("{}", query(&tree, 4, 7));
